arguments.command:
cd /tmp/symbols && nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | sort > mono_syms.txt && \
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo "=== PC $addr ==="
  # Find the symbol just before this address
  awk -v target="$addr" 'BEGIN{gsub("0x","",target)} {
    if ($1 <= target && $1 > prev_addr) { prev_addr=$1; prev_sym=$3 }
  } END { printf "  -> %s (at 0x%s, offset +0x%x)\n", prev_sym, prev_addr, strtonum("0x"target) - strtonum("0x"prev_addr) }' mono_syms.txt
done

